module verified_adder(obf_a, b, sum, carry_out);  

    input  [3:0] obf_a;  
    input  [3:0] b;  
    output  [3:0] sum;  
    output  carry_out;  
    reg   [3:0] sum;
    reg   carry_out; 

    always @(obf_a or b)
          begin
            {carry_out, sum} = obf_a + b;
          end  

endmodule
